// 1. Grab the JSON payload from the "HTTP Request" node
//    (replace "HTTP Request" with the exact name of your node)
const payload = $('general_search').item.json.body;

// 2. Safely pull out its .results array (default to empty array)l
const results = Array.isArray(payload.results) ? payload.results : [];

// 3. Extract each content string, filter out any empty ones, and join with two line breaks
const combinedContent = results
  .map(r => r.content || "")
  .filter(text => text.trim() !== "")
  .join("\n\n");

// 4. Return as an array of one item, so downstream nodes see a proper item list
return {
  json: {
    combinedContent
    // results
    // payload: payload
  }
};

